module top_module(
    clk,
    a,
    b,
    op,
    clear,
    result
);input clk;
input [7:0] a;
input [7:0] b;
input [1:0] op;
input clear;
output reg [7:0] result;

always @(posedge clk) begin
    if (clear) begin
        result <= 8'b0;
    end else begin
        case (op)
            2'b00: result <= a + b;
            2'b01: result <= a - b;
            2'b10: result <= a * b;
            2'b11: result <= a / b;
        endcase
    end
end

endmodule
